import React, { useState, useEffect } from "react";
import { Routes, Route, Link, useLocation, useNavigate } from "react-router-dom";
import "./App.css";
import Login from "./components/Login";
import Register from "./components/Register";
import Profile from "./components/Profile";
import Logo from "./assets/logo.jpeg";
import AdminDashboard from "./components/AdminDashboard";

import Pathology from "./components/Pathology";
import BloodBank from "./components/BloodBank";
import Consultancy from "./components/Consultancy";
import Medicine from "./components/Medicine";

import PathologyPage from "./components/PathologyPage";
import BloodBankPage from "./components/BloodBankPage";
import ConsultancyPage from "./components/ConsultancyPage";
import MedicinePage from "./components/MedicinePage";
import About from "./components/About";
import Contact from "./components/Contact";

import pathologyImg from "./assets/pathology.jpg";
import bloodbankImg from "./assets/bloodbank.jpg";
import consultancyImg from "./assets/consultancy.jpg";
import medicineImg from "./assets/medicine.jpg";


// âś… Added these â€” theyâ€™ll live in /components
import EditProfile from "./components/EditProfile";
import History from "./components/History";
import Orders from "./components/Orders";
import Wishlist from "./components/Wishlist";

function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [showRegister, setShowRegister] = useState(false);
  const [user, setUser] = useState(null);
  const [currentSlide, setCurrentSlide] = useState(0);
  const location = useLocation();
  const navigate = useNavigate();

  const slides = [
    require("./assets/hero-bg-1.jpg"),
    require("./assets/hero-bg-2.jpg"),
    require("./assets/hero-bg-3.jpg"),
    require("./assets/hero-bg-4.jpg"),
  ];

  useEffect(() => {
    const savedUser = localStorage.getItem("user");
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 4000);
    return () => clearInterval(interval);
  }, [slides.length]);

  const handleAuthSuccess = (userData) => {
    setUser(userData);
    localStorage.setItem("user", JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem("token");
    localStorage.removeItem("user");
  };

  const hideHeader =
    location.pathname === "/login" || location.pathname === "/register";
  const isHome = location.pathname === "/";

  return (
    <div className="app">
      {/* ===== HEADER ===== */}
      {!hideHeader && isHome && (
        <header className="header fixed-header">
          <div className="logo-container">
            <img src={Logo} alt="HEALink Logo" className="logo" />
            <h1>HEALink</h1>
          </div>

          <nav>
            <ul>
              <li>
                <Link to="/" className="nav-link">Home</Link>
              </li>
              <li>
                <a href="#about-section" className="nav-link">About</a>
              </li>
              <li>
                <Link to="/contact" className="nav-link">Contact</Link>
              </li>
            </ul>
          </nav>

          <div className="auth-buttons">
            {user ? (
              <Profile user={user} onLogout={handleLogout} />
            ) : (
              <>
                <button className="login-btn" onClick={() => setShowLogin(true)}>
                  Login
                </button>
                <button
                  className="register-btn"
                  onClick={() => setShowRegister(true)}
                >
                  Register
                </button>
              </>
            )}
          </div>
        </header>
      )}

      {/* ===== BACK BUTTON (for non-home pages) ===== */}
      {!isHome && !hideHeader && (
        <button className="back-floating-btn" onClick={() => navigate(-1)}>
          â¬… Back
        </button>
      )}

      {/* ===== ROUTES ===== */}
      <Routes>
        <Route
          path="/"
          element={
            <>
              <section className="hero">
                <div className="hero-content">
                  <h2>Your Health, Our Priority</h2>
                  <p>Connecting people to better healthcare solutions.</p>
                  <button
                    onClick={() =>
                      document
                        .querySelector(".sections")
                        ?.scrollIntoView({ behavior: "smooth" })
                    }
                    className="get-started-btn"
                  >
                    Get Started
                  </button>
                </div>

                <div className="hero-slider">
                  {slides.map((src, index) => (
                    <img
                      key={index}
                      src={src}
                      alt={`Slide ${index + 1}`}
                      className={`fade-slide ${
                        index === currentSlide ? "active" : ""
                      }`}
                    />
                  ))}
                </div>
              </section>

              <About />


              <section className="sections timeline">

  {/* Row 1: Card LEFT, Image RIGHT */}
  <div className="timeline-row">
    <div className="timeline-card">
      <Pathology />
    </div>
    <div className="timeline-image">
      <img src={pathologyImg} alt="Pathology" />
    </div>
  </div>

  {/* Row 2: Image LEFT, Card RIGHT */}
  <div className="timeline-row reverse">
    <div className="timeline-image">
      <img src={bloodbankImg} alt="Blood Bank" />
    </div>
    <div className="timeline-card">
      <BloodBank />
    </div>
  </div>

  {/* Row 3: Card LEFT, Image RIGHT */}
  <div className="timeline-row">
    <div className="timeline-card">
      <Consultancy />
    </div>
    <div className="timeline-image">
      {/*<img src={consultancyImg} alt="Consultancy" />*/}
    </div>
  </div>

  {/* Row 4: Image LEFT, Card RIGHT */}
  <div className="timeline-row reverse">
    <div className="timeline-image">
      {/*<img src={medicineImg} alt="Medicine" />*/}
    </div>
    <div className="timeline-card">
      <Medicine />
    </div>
  </div>

</section>

            </>
          }
        />

        <Route path="/pathology" element={<PathologyPage />} />
        <Route path="/bloodbank" element={<BloodBankPage />} />
        <Route path="/consultancy" element={<ConsultancyPage />} />
        <Route path="/medicine" element={<MedicinePage />} />
        <Route path="/contact" element={<Contact />} />

        {/* âś… Added these routes for dropdown redirects */}
        <Route path="/edit-profile" element={<EditProfile />} />
        <Route path="/history" element={<History />} />
        <Route path="/orders" element={<Orders />} />
        <Route path="/wishlist" element={<Wishlist />} />
        <Route path="/admin" element={<AdminDashboard />} />
      </Routes>

      {!hideHeader && (
        <footer className="footer">
          <p>Â© 2025 HEALink. All rights reserved.</p>
        </footer>
      )}

      {showLogin && (
        <Login
          onClose={() => setShowLogin(false)}
          onLoginSuccess={(userData) => {
            handleAuthSuccess(userData);
            setShowLogin(false);
          }}
        />
      )}

      {showRegister && (
        <Register
          onClose={() => setShowRegister(false)}
          onRegisterSuccess={(userData) => {
            handleAuthSuccess(userData);
            setShowRegister(false);
          }}
        />
      )}
    </div>
  );
}

export default App;
